import { useCallback, useEffect, useRef } from 'react';
import {
  DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS,
  scrollCueAnchorIntoView,
  type CueAnchorActivationOptions,
} from './scrollCueAnchor';

export type ScrollCueAnchorOptions = CueAnchorActivationOptions;

export const useScrollCueAnchorWhenActive = (
  isActive: boolean,
  options: ScrollCueAnchorOptions = DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS,
): ((element: HTMLDivElement | null) => void) => {
  const { manageFocus, scrollIntoView } = { ...DEFAULT_CUE_ANCHOR_ACTIVATION_OPTIONS, ...options };
  const anchorRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (isActive && anchorRef.current) {
      scrollCueAnchorIntoView(anchorRef.current, { manageFocus, scrollIntoView });
    }
  }, [isActive, manageFocus, scrollIntoView]);

  return useCallback((element: HTMLDivElement | null) => {
    anchorRef.current = element;
  }, []);
};
